//! D.PEEL.ORCHESTRATOR.1 — Nested peel architecture.
//!
//! Three manifolds. Three dimensionalities. Three peel loops.
//! The orchestrator calls them in sequence: value → object → cell.
//! Each outer peel constrains the next inner peel.
//!
//! The value peel finds WHAT colors transform (k dimensions).
//! The object peel finds WHERE objects move (n dimensions).
//! The cell peel assembles the exact grid (rows × cols dimensions).
//!
//! Understanding = all three levels converge.

pub mod value;
pub mod object;
pub mod cell;

use crate::engine::{Q, Delta, ComposedOperator};
use crate::perception;
use super::{SenseData, CompositionRecord, GeneratorSource};
