/// Unified result from the nested peel architecture.
pub struct NestedPeelResult {
    /// The derived output grid (if test input was provided).
    pub derived_output: Option<Vec<i64>>,
    /// The residual as Q for the cognition pipeline.
    pub residual: Q,
    /// Number of generators applied across all levels.
    pub generators_applied: usize,
    /// The category-level T Delta (for membrane recording).
    pub t_delta: Delta,
    /// Composition records (for vocabulary inscription).
    pub compositions: Vec<CompositionRecord>,
    /// Which generator source achieved the result.
    pub winning_source: Option<GeneratorSource>,
    /// Per-level cocycle residuals.
    pub value_cocycle: i64,
    pub object_cocycle: i64,
    pub cell_l1: u64,
    /// Per-level torsion orders.
    /// Value torsion: period of the color permutation.
    /// Object torsion: period of the spatial symmetry.
    /// Full torsion: lcm(value, object).
    pub value_torsion: u16,
    pub object_torsion: u16,
    pub full_torsion: u16,
    /// Whether understanding was achieved.
    pub understood: bool,
}

/// Run the nested peel architecture: value → object → cell.
///
/// This is the Phase 4 replacement for peel_manifold_with_senses.
/// Each level operates on its own manifold with its own dimensionality
/// and its own torsion. The compound of all three IS the understanding.
pub fn nested_peel(
    train_pairs: &[(Vec<i64>, Vec<i64>)],
    test_input: Option<&[i64]>,
    rows: usize,
    cols: usize,
    senses: &SenseData,
) -> NestedPeelResult {
    // Partition genomic operators by level.
    // Value-level ops: those with sigma (value map) but no spatial remap.
    // Spatial-level ops: those with spatial opcode.
    // This partition is approximate — the algebra determines the true level.
    // Partition vocabulary by level:
    // Value-only: opcode outside SpatialPrimitive range (0-9) OR opcode 0 with sigma.
    // Spatial: opcode in SpatialPrimitive range (0-9) — these carry real spatial transforms.
    // opcode 255 = value-only identity spatial (from partial inscription).
    let value_ops: Vec<ComposedOperator> = senses.composed_operators.iter()
        .filter(|op| !op.sigma.is_empty() && (op.opcode > 9 || op.opcode == 0))
        .cloned().collect();

    let spatial_ops: Vec<ComposedOperator> = senses.composed_operators.iter()
        .filter(|op| op.opcode > 0 && op.opcode <= 9)
        .cloned().collect();

    // ── Outer Peel: Value Manifold ──
    let value_result = value::peel_value_manifold(
        train_pairs, rows, cols, &value_ops,
    );

    // ── Middle Peel: Object Manifold ──
    let touch_source = senses.touch_source.clone()
        .unwrap_or_else(|| perception::compute_adjacency_structure(&train_pairs[0].0, rows, cols));
    let touch_target = senses.touch_target.clone()
        .unwrap_or_else(|| perception::compute_adjacency_structure(&train_pairs[0].1, rows, cols));

    let object_result = object::peel_object_manifold(
        train_pairs,
        test_input,
        rows, cols,
        &value_result.category_map,
        &touch_source,
        &touch_target,
        &spatial_ops,
    );

    // ── Inner Peel: Cell Manifold ──
    let cell_result = cell::peel_cell_manifold(
        &object_result.transformed_pairs,
        object_result.transformed_test.as_deref(),
        rows, cols,
        &value_result.category_map,
        value_result.thoughts_evaluated,
        object_result.thoughts_evaluated,
    );

    // ── Build T Delta at category level for the membrane ──
    let mut unique_vals: Vec<i64> = Vec::new();
    for &v in &train_pairs[0].0 {
        if !unique_vals.contains(&v) { unique_vals.push(v); }
    }
    unique_vals.sort();
    let k = unique_vals.len();

    let src_ent: Vec<Vec<Q>> = unique_vals.iter()
        .map(|&v| vec![Q::new(BigInt::from(v), BigInt::from(1))])
        .collect();
    let tgt_vals: Vec<i64> = value_result.category_map.iter().map(|(_, t)| *t).collect();
    let tgt_ent: Vec<Vec<Q>> = tgt_vals.iter()
        .map(|&v| vec![Q::new(BigInt::from(v), BigInt::from(1))])
        .collect();
    let source_cat = perception::encode_relational(&src_ent);
    let target_cat = perception::encode_relational(&tgt_ent);
    let cat_m = source_cat.m;
    let mut t_delta = Delta::zero(k, cat_m);
    for i in 0..k {
        for j in 0..k {
            for l in 0..cat_m {
                t_delta.entries[i][j][l] = &target_cat.entries[i][j][l] - &source_cat.entries[i][j][l];
            }
        }
    }

    // ── Compose residual ──
    let residual = Q::new(
        BigInt::from(cell_result.l1_residual),
        BigInt::from(1u64),
    );

    // Compose full torsion: lcm(value_torsion, object_torsion)
    let vt = value_result.torsion_order as u64;
    let ot = object_result.torsion_order as u64;
    let full_torsion = {
        let (mut a, mut b) = (vt, ot);
        while b != 0 { let t = b; b = a % b; a = t; }
        (vt / a * ot).min(256) as u16
    };

    // Record composition from the object peel's winning spatial thought.
    // This is where spatial opcodes enter the vocabulary pipeline.
    // Without this, compositions is always empty and inscription falls back to 255.
    let mut compositions = Vec::new();
    let spatial_opcode = match &object_result.best_thought {
        super::vocabulary::Thought::ReflectHorizontal => Some(0u8),
        super::vocabulary::Thought::ReflectVertical => Some(1u8),
        super::vocabulary::Thought::Translate(_, _) => Some(2u8),
        super::vocabulary::Thought::Rotate90 => Some(3u8),
        super::vocabulary::Thought::Rotate180 => Some(4u8),
        super::vocabulary::Thought::Rotate270 => Some(5u8),
        super::vocabulary::Thought::Genomic { opcode, .. } => Some(*opcode),
        _ => None,
    };
    spatial_opcode.map(|opcode| {
        // Build sigma from the value category map
        let sigma: Vec<(i16, i16)> = value_result.category_map.iter()
            .map(|&(from, to)| (from as i16, to as i16))
            .collect();
        compositions.push(CompositionRecord {
            operator: opcode,
            parameter: 0,
            depth: cell_result.composition_depth,
            sigma_post: sigma,
        });
    });

    NestedPeelResult {
        derived_output: cell_result.derived_output,
        residual,
        generators_applied: cell_result.composition_depth,
        t_delta,
        compositions,
        winning_source: spatial_opcode.map(|_| GeneratorSource::Vision),
        value_cocycle: value_result.cocycle_residual,
        object_cocycle: object_result.cocycle_residual,
        cell_l1: cell_result.l1_residual,
        value_torsion: value_result.torsion_order,
        object_torsion: object_result.torsion_order,
        full_torsion,
        understood: cell_result.understood,
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn make_sense_data() -> SenseData {
        SenseData::empty()
    }

    #[test]
    fn test_value_peel_identity() {
        // Input = output: the value peel should find identity (zero cocycle residual)
        let pairs = vec![
            (vec![1, 2, 3, 4], vec![1, 2, 3, 4]),
        ];
        let result = value::peel_value_manifold(&pairs, 2, 2, &[]);
        assert_eq!(result.cocycle_residual, 0, "Identity should have zero cocycle residual");
        assert_eq!(result.torsion_order, 1, "Identity has torsion order 1");
    }

    #[test]
    fn test_value_peel_uniform_shift() {
        // Each value shifted by +1: the value peel should find UniformShift(1)
        let pairs = vec![
            (vec![1, 2, 3, 0], vec![2, 3, 4, 1]),
        ];
        let result = value::peel_value_manifold(&pairs, 2, 2, &[]);
        assert_eq!(result.cocycle_residual, 0, "Uniform shift should have zero cocycle residual");
    }

    #[test]
    fn test_nested_peel_identity() {
        // Input = output: full nested peel should achieve understanding
        let pairs = vec![
            (vec![1, 2, 3, 4], vec![1, 2, 3, 4]),
        ];
        let test = vec![5, 6, 7, 8];
        let senses = make_sense_data();
        let result = nested_peel(&pairs, Some(&test), 2, 2, &senses);
        assert!(result.understood, "Identity should be understood");
        assert_eq!(result.cell_l1, 0, "Identity should have zero L1");
    }

    #[test]
    fn test_torsion_composition() {
        // Value torsion 2, object torsion 4 → full torsion lcm(2,4) = 4
        let pairs = vec![
            (vec![1, 2, 1, 2], vec![1, 2, 1, 2]),
        ];
        let senses = make_sense_data();
        let result = nested_peel(&pairs, Some(&vec![1, 2, 1, 2]), 2, 2, &senses);
        // Identity: all torsion orders should be 1
        assert_eq!(result.value_torsion, 1);
        assert_eq!(result.object_torsion, 1);
        assert_eq!(result.full_torsion, 1);
    }
}
